module RefModule(clk, rst, en, D, Q);
    input clk;
    input rst;
    input en;
    input [31:0] D;
    output reg [31:0] Q;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst)
            Q <= 32'b0;
        else if (en)
            Q <= D;
    end
endmodule
